/** @type {import('jest').Config} */
module.exports = {
  testEnvironment: 'node',
  roots: ['<rootDir>/tests'],
  testMatch: ['**/*.test.js'],
  testTimeout: 2000,
  collectCoverage: true,
  collectCoverageFrom: ['src/**/*.js'],
  coverageThreshold: {
    global: {
      branches: 80,
      functions: 80,
      lines: 80,
      statements: 80,
    },
  },
  coverageReporters: ['text-summary', 'lcov'],
};

'use strict';

function add(a, b) {
  return a + b;
}

function subtract(a, b) {
  return a - b;
}

function multiply(a, b) {
  return a * b;
}

function divide(a, b) {
  if (b === 0) {
    throw new Error('cannot divide by zero');
  }
  return a / b;
}

function percentage(part, whole) {
  if (whole === 0) {
    throw new Error('cannot compute percentage of zero');
  }
  return (part / whole) * 100;
}

function average(values) {
  if (values.length === 0) {
    throw new Error('cannot average an empty list');
  }
  return values.reduce((a, b) => a + b, 0) / values.length;
}

module.exports = { add, subtract, multiply, divide, percentage, average };

'use strict';

const { add, subtract, multiply, divide } = require('../src/math_ops');

describe('add', () => {
  it('adds positive numbers', () => {
    expect(add(2, 3)).toBe(5);
  });
  it('handles negatives', () => {
    expect(add(-1, 1)).toBe(0);
  });
  it('handles floats', () => {
    expect(add(0.5, 0.25)).toBe(0.75);
  });
});

describe('subtract', () => {
  it('subtracts positives', () => {
    expect(subtract(5, 3)).toBe(2);
  });
  it('goes negative', () => {
    expect(subtract(0, 10)).toBe(-10);
  });
});

describe('multiply', () => {
  it('multiplies positives', () => {
    expect(multiply(2, 3)).toBe(6);
  });
  it('handles negatives', () => {
    expect(multiply(-1, 5)).toBe(-5);
  });
  it('handles zero', () => {
    expect(multiply(0, 100)).toBe(0);
  });
});

describe('divide', () => {
  it('divides cleanly', () => {
    expect(divide(6, 3)).toBe(2);
  });
  it('handles fractions', () => {
    expect(divide(1, 4)).toBe(0.25);
  });
  it('throws on zero denominator', () => {
    expect(() => divide(1, 0)).toThrow('cannot divide by zero');
  });
});

